class Solution {
public:
    bool canChange(string start, string target) {
        int n = start.size();
        int i = 0, j = 0;
        while (i < n || j < n) {
            while (i < n && start[i] == '_') ++i;
            while (j < n && target[j] == '_') ++j;
            if (i == n && j == n) return true;
            if (i == n || j == n) return false;
            if (start[i] != target[j]) return false;
            if (start[i] == 'L' && i < j) return false;
            if (start[i] == 'R' && i > j) return false;
            ++i; ++j;
        }
        return true;
    }
};
```
efficiency: HIGH
time complexity: O(n)
space complexity: O(1)
energy implications: LOW
explanation: Two-pointer sweep: skip underscores, then verify that every non-underscore character matches and that each 'L' in start is not to the right of its target position and each 'R' is not to the left. Linear pass, constant memory.

